Hey, I've got a React component that's feeling sluggish when the product list gets large (we have ~2000 products). Can you review it?

```tsx
import React, { useState, useEffect, useContext } from 'react';
import { AppContext } from '../context/AppContext';

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
  inStock: boolean;
}

export function ProductList() {
  const { user, theme, notifications, cart, settings } = useContext(AppContext);
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState('name');

  useEffect(() => {
    fetch('/api/products')
      .then(res => res.json())
      .then(data => setProducts(data));
  }, []);

  const filteredProducts = products
    .filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
      if (sortBy === 'price') return a.price - b.price;
      return a.name.localeCompare(b.name);
    });

  return (
    <div style={{ background: theme.background }}>
      <input
        value={search}
        onChange={e => setSearch(e.target.value)}
        placeholder="Search products..."
      />
      <select onChange={e => setSortBy(e.target.value)}>
        <option value="name">Name</option>
        <option value="price">Price</option>
      </select>
      <div>
        {filteredProducts.map(product => (
          <ProductCard
            key={product.id}
            product={product}
            onAddToCart={() => cart.add(product)}
            style={{ color: theme.textColor, padding: '16px' }}
          />
        ))}
      </div>
    </div>
  );
}
```

We're building a SaaS platform and I need a security review of our authentication middleware and user endpoint. This is in production with paying customers.

```typescript
import express from 'express';
import jwt from 'jsonwebtoken';
import mysql from 'mysql2';

const JWT_SECRET = 'super-secret-key-2024';
const db = mysql.createConnection({ host: 'localhost', user: 'root', password: 'admin123', database: 'saas_app' });

function authMiddleware(req: any, res: any, next: any) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'No token' });
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token', details: err.message });
  }
}

app.get('/api/users/:id', authMiddleware, async (req, res) => {
  const userId = req.params.id;
  const [rows] = await db.promise().query(
    `SELECT * FROM users WHERE id = ${userId}`
  );
  if (rows.length === 0) return res.status(404).json({ error: 'User not found' });
  res.json(rows[0]);
});

app.post('/api/users/:id/password', authMiddleware, async (req, res) => {
  const { currentPassword, newPassword } = req.body;
  const userId = req.params.id;
  const [rows] = await db.promise().query(
    `SELECT password FROM users WHERE id = ${userId}`
  );
  if (rows[0].password === currentPassword) {
    await db.promise().query(
      `UPDATE users SET password = '${newPassword}' WHERE id = ${userId}`
    );
    res.json({ message: 'Password updated' });
  } else {
    res.status(403).json({ error: 'Wrong password' });
  }
});
